// pages/CourseDetail.jsx
import { useParams, useNavigate } from 'react-router-dom';

function CourseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();

  const handleGoBack = () => {
    navigate(-1); // Retour à la page précédente
  };

  const handleGoToCourses = () => {
    navigate('/formations'); // Navigation directe
  };

  return (
    &lt;div&gt;
      &lt;h1&gt;Détail de la formation #{id}&lt;/h1&gt;
      &lt;button onClick={handleGoBack}&gt;
        ← Retour
      &lt;/button&gt;
      &lt;button onClick={handleGoToCourses}&gt;
        Voir toutes les formations
      &lt;/button&gt;
    &lt;/div&gt;
  );
}
```

**Explication de `useNavigate()` :**
- `navigate(-1)` : retour à la page précédente (comme historique navigateur)
- `navigate('/chemin')` : navigation directe vers une route
- `navigate('/chemin', { replace: true })` : remplace l'entrée courante dans l'historique
- `navigate('/formation/5', { state: { from: 'list' } })` : passe des données via l'état

**Utilité :** Navigation après soumission de formulaire, redirection après connexion, boutons d'action personnalisés.

