// components/ProtectedRoute.jsx
import { Navigate } from 'react-router-dom';

function ProtectedRoute({ children, isAuthenticated, redirectTo = '/login' }) {
  if (!isAuthenticated) {
    return &lt;Navigate to={redirectTo} replace /&gt;;
  }
  return children;
}

// App.jsx (modification)
function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  // ... logique d'authentification

  return (
    &lt;BrowserRouter&gt;
      &lt;Routes&gt;
        &lt;Route path="/" element={&lt;Layout /&gt;}&gt;
          &lt;Route index element={&lt;Home /&gt;} /&gt;
          &lt;Route path="formations" element={&lt;CoursesList /&gt;} /&gt;
          &lt;Route path="formation/:id" element={&lt;CourseDetail /&gt;} /&gt;
          &lt;Route path="a-propos" element={&lt;About /&gt;} /&gt;
          &lt;Route path="contact" element={&lt;Contact /&gt;} /&gt;
          &lt;Route path="login" element={&lt;LoginPage setAuth={setIsAuthenticated} /&gt;} /&gt;
        &lt;/Route&gt;

        {/* Routes admin PROTÉGÉES */}
        &lt;Route
          path="admin"
          element={
            &lt;ProtectedRoute isAuthenticated={isAuthenticated}&gt;
              &lt;AdminLayout /&gt;
            &lt;/ProtectedRoute&gt;
          }
        &gt;
          &lt;Route index element={&lt;AdminDashboard /&gt;} /&gt;
          &lt;Route path="courses" element={&lt;AdminCourses /&gt;} /&gt;
          &lt;Route path="users" element={&lt;AdminUsers /&gt;} /&gt;
        &lt;/Route&gt;

        &lt;Route path="*" element={&lt;NotFound /&gt;} /&gt;
      &lt;/Routes&gt;
    &lt;/BrowserRouter&gt;
  );
}
```

**Explication :**
- `ProtectedRoute` est un composant wrapper qui vérifie l'authentification
- Si non authentifié : `<Navigate to="/login" replace />` redirige l'utilisateur
- `replace` remplace l'entrée courante dans l'historique (évite de revenir à la page protégée avec le bouton retour)
- Les routes admin sont enveloppées par ce composant
- La page `/login` doit permettre de définir `isAuthenticated` à true après connexion

**Stratégie de migration :**

**1. Transformation des pages en composants :**
| Page originale | Composant React | Route associée |
|----------------|-----------------|----------------|
| index.html | `<Home />` | `/` |
| about.html | `<About />` | `/about` |
| products.html | `<ProductsList />` | `/products` |
| product-detail.html?id=5 | `<ProductDetail />` | `/product/:id` |
| contact.html | `<Contact />` | `/contact` |

**2. Remplacement des liens :**
- Ancien : `<a href="about.html">À propos</a>`
- Nouveau : `<Link to="/about">À propos</Link>`

**3. Conversion des paramètres :**
- Ancien : `product-detail.html?id=5`
- Nouveau : `/product/5` (paramètre d'URL)
- Récupération : `useParams()` au lieu de `URLSearchParams`

**4. Configuration du serveur :**
- Nécessite une redirection (catch-all) vers `index.html` pour gérer les URLs directes
- Exemple avec Nginx :
```nginx
location / {
  try_files $uri /index.html;
}
```

**5. Code de migration :**
